import hashlib
import os

def generate_hash(file_path):
    try:
        with open(file_path, 'rb') as f:
            md5 = hashlib.md5()
            for chunk in iter(lambda: f.read(4096), b""):
                md5.update(chunk)
        return md5.hexdigest()
    except FileNotFoundError:
        print(f"File {file_path} not found")
        return None